# Example task: Write a models package (domain types only, standard library only) defining MULTIPLE exported domain types in ONE file with JSON tags: an entity struct (ID, Title/Name, Status string; valid status from a fixed set) AND a separate Event struct {Type, TaskID string} for the event seam, plus an exported sentinel var ErrInvalid = errors.New and a (t Entity) Validate() error method wrapping ErrInvalid via fmt.Errorf on empty or invalid fields. EVERY type the file's spec names must exist here — other packages import and reference them (never omit the Event type).
```go
package models

import (
	"errors"
	"fmt"
)

// ErrInvalid is the sentinel wrapped by every validation failure.
var ErrInvalid = errors.New("invalid")

// Order is a domain entity with a lifecycle status.
type Order struct {
	ID     string `json:"id"`
	Status string `json:"status"`
}

// Event is a SEPARATE domain type in the SAME package — a package often holds
// more than one type; define EVERY type the spec lists, not just the first.
type Event struct {
	Type    string `json:"type"`
	OrderID string `json:"order_id"`
}

// Validate reports whether the order is well-formed, wrapping ErrInvalid.
func (o Order) Validate() error {
	if o.ID == "" {
		return fmt.Errorf("%w: id is required", ErrInvalid)
	}
	if o.Status != "open" && o.Status != "shipped" && o.Status != "closed" {
		return fmt.Errorf("%w: bad status %q", ErrInvalid, o.Status)
	}
	return nil
}
```
# Example task: Write a package main bearer-token auth middleware (standard library only): Auth(token string) returning func(http.Handler) http.Handler that rejects requests without a valid `Authorization: Bearer <token>` header with 401 (constant-time compare) and passes valid requests to the wrapped next handler. Compose it as Auth(token)(mux).
```go
// Package main shows the standard bearer-token auth middleware shape: a
// constructor returning func(http.Handler) http.Handler so it composes with
// any mux, and a constant-time token compare.
package main

import (
	"crypto/subtle"
	"net/http"
)

// Auth returns middleware enforcing `Authorization: Bearer <token>` on every
// request. Constructed once with the expected token, it WRAPS the next
// handler — callers compose it as Auth(token)(mux), they never invoke the
// middleware with (w, r) directly:
//
//	protected := Auth("secret")(mux)
func Auth(token string) func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			got, ok := bearerToken(r)
			if !ok || subtle.ConstantTimeCompare([]byte(got), []byte(token)) != 1 {
				http.Error(w, "unauthorized", http.StatusUnauthorized)
				return
			}
			next.ServeHTTP(w, r)
		})
	}
}

func bearerToken(r *http.Request) (string, bool) {
	const prefix = "Bearer "
	h := r.Header.Get("Authorization")
	if len(h) <= len(prefix) || h[:len(prefix)] != prefix {
		return "", false
	}
	return h[len(prefix):], true
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("GET /health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})
	_ = Auth("secret")(mux) // wire into an http.Server in a real backend
}
```

