	w := do(t, h, "GET", "/tasks", "")
	if w.Code != http.StatusOK {
		t.Fatalf("list tasks: want 200, got %d", w.Code)
	}
	var tasks []Task
	json.Unmarshal(w.Body.Bytes(), &tasks)
	if len(tasks) != 2 {
		t.Fatalf("list tasks len: want 2, got %d", len(tasks))
