	do(t, h, "POST", "/tasks", `{"id":"2","title":"Task 2","status":"doing","project_id":"2"}`)
	do(t, h, "POST", "/tasks", `{"id":"3","title":"Task 3","status":"done","project_id":"3"}`)
	w := do(t, h, "GET", "/tasks?limit=1", "")
	if w.Code != http.StatusOK {
